import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';

function PartnerDashboard() {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      const response = await partnerService.getDashboard();
      setDashboard(response.data);
    } catch (err) {
      console.error('Dashboard error:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div style={{ padding: '2rem', textAlign: 'center' }}>
        <h2>Loading...</h2>
      </div>
    );
  }

  return (
    <div style={{ padding: '2rem' }}>
      <h1>Partner Dashboard</h1>
      <p>Welcome to your partner dashboard!</p>

      <div style={{ marginTop: '2rem', padding: '1rem', background: '#f5f5f5', borderRadius: '8px' }}>
        <h3>Stats</h3>
        <p>Total Sales: {dashboard?.stats?.totalSales || 0}</p>
        <p>Total Revenue: ₹{dashboard?.stats?.totalRevenue || 0}</p>
        <p>Total Commission: ₹{dashboard?.stats?.totalCommission || 0}</p>
      </div>

      {(!dashboard?.recentSales || dashboard.recentSales.length === 0) && (
        <div style={{ marginTop: '2rem', textAlign: 'center', color: '#999' }}>
          <h3>No Sales Yet</h3>
          <p>Start selling products to see your performance!</p>
        </div>
      )}
    </div>
  );
}

export default PartnerDashboard;
